// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
contract GetSumSolidity{
    //memory存储
    function getSumMemory(uint[] memory data) public pure returns (uint){
        uint sum=0;
        for(uint i=0;i<data.length;i++){
            sum=sum+data[i];
        }
        return sum;
    }
      //calldate存储
    function getSumCalldata(uint[] calldata data) public pure returns (uint){
        uint sum=0;
        for(uint i=0;i<data.length;i++){
            sum=sum+data[i];
        }
        return sum;
    }
}

contracts/2.1/01bool/AccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
contract AccessControl{
    //默认是激活状态
    bool isActive=true;
    //默认是非停止状态
    bool isPause=false;
    //检查是否为正常状态
    function checkActive() public view returns (bool){
        return isActive&&!isPause;
    }
    //切换状态
    function toggleActive() public {
        isActive=!isActive;
    }
    //判断是否为正常状态
    function isNormal() public view returns (string memory){
        return checkActive()?unicode"正常状态>>>":unicode"不正常状态----";
    }
}

