// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
contract AddressConversion{
    //address-->address payable
    function address2PayableAddress(address addr) public pure returns(address){
        return payable(addr);
    }
     //address payable-->address
    function payableAddress2Address(address payable  addr) public pure returns(address){
        return address(addr);
    }
    //address-->uint160
    function address2Uint160(address addr) public pure returns(uint160){
        return uint160(addr);
    }
    //uint160-->address
    function uint1602Address(uint160 addr) public pure returns (address){
        return address(addr);
    }
}

contracts/2.1/04byte&string/DynamicBytes.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
contract DynamicBytes{
    bytes public data;
    //添加元素
    function addBytes() public {
        data.push(0x12);
    }
    //获取长度
    function getLength() public view returns (uint256){
        return data.length;
    }
    //访问元素
    function accessBytes(uint index) public view returns(bytes1){
        require(index<data.length,unicode"数组下标越界");
        return data[index];
    }
    //删除元素
    function popBytes() public {
        require(data.length!=0,unicode"数组为空");
        data.pop();
    }
}

